export const COUNTRY_SHAPE_KEYS = ["iran","israel","sudan","ukraine","syria","colombia","taiwan","lebanon"] as const satisfies readonly CountryShapeKey[];

export const countryShapeIso3: Record<CountryShapeKey, string> = {
  iran: "IRN",
  israel: "ISR",
  sudan: "SDN",
  ukraine: "UKR",
  syria: "SYR",
  colombia: "COL",
  taiwan: "TWN",
  lebanon: "LBN",
};

export const countryShapeKeyByIso3: Record<string, CountryShapeKey> = Object.fromEntries(
  Object.entries(countryShapeIso3).map(([shapeKey, iso3]) => [iso3, shapeKey as CountryShapeKey]),
);

export function getCountryShapeKey(iso3: string): CountryShapeKey | null {
  return countryShapeKeyByIso3[iso3.toUpperCase()] ?? null;
}

